/**
 * Specifies the view which the ColorPicker will render in the popup
 * ([see example](components/inputs/colorpicker/views)).
 *
 * The possible values are:
 * * `palette`
 * * `gradient`
 * * **Deprecated** `combo`
 */
export type ColorPickerView = 'gradient' | 'palette' | 'combo';
